import subprocess
import os

def generate_requirements_txt():
    """Generates a requirements.txt file with hashes for all installed packages."""
    with open('requirements.txt', 'w') as f:
        subprocess.run(['pip', 'freeze', '--require-hashes'], stdout=f)

def update_requirements_txt():
    """Updates the requirements.txt file with the latest versions of packages."""
    subprocess.run(['pip', 'install', '--upgrade', '-r', 'requirements.txt'])
    generate_requirements_txt()

def install_dependencies():
    """Installs dependencies from requirements.txt."""
    subprocess.run(['pip', 'install', '-r', 'requirements.txt'])

def generate_poetry_lock():
    """Generates a poetry.lock file for the project."""
    subprocess.run(['poetry', 'lock'])

def update_poetry_lock():
    """Updates the poetry.lock file with the latest versions of packages."""
    subprocess.run(['poetry', 'update'])

def install_poetry_dependencies():
    """Installs dependencies from poetry.lock."""
    subprocess.run(['poetry', 'install'])

def main():
    """Main function to manage dependencies."""
    if not os.path.exists('requirements.txt'):
        generate_requirements_txt()
    else:
        update_requirements_txt()

    if not os.path.exists('poetry.lock'):
        generate_poetry_lock()
    else:
        update_poetry_lock()

if __name__ == "__main__":
    main()